INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1300, 'Episode 1: Perintah Menyembelih Sapi dan Banyaknya Pertanyaan', 'Tim Editorial ULYAH', 'ebooks/kisah-sapi-betina/id/kisah-sapi-betina-01-perintah-dan-banyak-bertanya.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-Baqarah 67-71 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: Perintah Menyembelih Sapi dan Banyaknya Pertanyaan', 'kisah-sapi-betina-01-perintah-dan-banyak-bertanya', 'id', 'kisah-sapi-betina', 1, 5, 'Di masa Nabi Musa, terjadi sebuah pembunuhan di kalangan Bani Israil dan pelakunya tidak diketahui. Maka Allah memerintahkan mereka menyembelih seekor sapi betina sebagai jalan mengungkap kebenaran. Namun mereka menyambutnya dengan keheranan, bahkan mengira Musa bergurau. Allah berfirman, "Dan (ingatlah) ketika Musa berkata kepada kaumnya, ‘Allah memerintahkan kamu agar menyembelih seekor sapi betina.’ Mereka bertanya, ‘Apakah engkau akan menjadikan kami sebagai ejekan?’ Dia (Musa) menjawab, ‘Aku berlindung kepada Allah agar tidak termasuk orang-orang yang bodoh’" (QS. Al-Baqarah: 67).

Seharusnya cukup bagi mereka menyembelih sapi betina apa saja. Tetapi mereka justru memperbanyak pertanyaan yang menyulitkan diri sendiri — tentang umurnya, lalu warnanya, lalu jenisnya. "Mereka berkata, ‘Mohonkanlah kepada Tuhanmu untuk kami agar Dia menjelaskan kepada kami tentang (sapi betina) itu.’ Dia (Musa) menjawab, ‘Sesungguhnya Allah berfirman bahwa sapi betina itu tidak tua dan tidak muda, (tetapi) pertengahan antara itu…’" (QS. Al-Baqarah: 68). Mereka bertanya lagi tentang warnanya, dan dijawab, "…sapi betina yang kuning tua warnanya, yang menyenangkan orang-orang yang memandangnya" (QS. Al-Baqarah: 69). Mereka masih bertanya lagi, dan akhirnya dijelaskan ciri yang sangat spesifik, "…(yaitu) sapi betina yang belum pernah dipakai untuk membajak tanah dan tidak (pula) untuk mengairi tanaman, sehat, dan tanpa belang." Barulah mereka berkata, "‘Sekarang barulah engkau menerangkan (hal) yang sebenarnya.’ Lalu mereka menyembelihnya, dan hampir saja mereka tidak melaksanakan (perintah) itu" (QS. Al-Baqarah: 71).

Hikmah: menaati perintah Allah dengan segera dan lapang dada adalah yang terbaik. Semakin mereka mempersulit dengan banyak bertanya dan berdalih, semakin Allah mempersempit pilihan mereka. Kemudahan ada pada ketaatan yang tulus, bukan pada mencari-cari alasan.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Al-Baqarah: 67-71 (teks & terjemahan quran-json). Latar pembunuhan yang menjadi sebab perintah ini disebut secara ringkas pada ayat berikutnya (72-73); rincian tambahan dalam sebagian riwayat berada di luar nas dan tidak dipastikan di sini.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 2 AND number = 67), 1300, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1301, 'Episode 1: The Command to Slaughter a Cow, and Their Many Questions', 'Tim Editorial ULYAH', 'ebooks/kisah-sapi-betina/en/kisah-sapi-betina-01-perintah-dan-banyak-bertanya.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-Baqarah 67-71 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: The Command to Slaughter a Cow, and Their Many Questions', 'kisah-sapi-betina-01-perintah-dan-banyak-bertanya', 'en', 'kisah-sapi-betina', 1, 5, 'In the time of Prophet Musa, a murder occurred among the Children of Israel and the killer was unknown. So Allah commanded them to slaughter a cow as a means of revealing the truth. But they met it with astonishment, even thinking Musa was joking. Allah said, "And when Musa said to his people, ‘Indeed, Allah commands you to slaughter a cow,’ they said, ‘Do you take us in ridicule?’ He said, ‘I seek refuge in Allah from being among the ignorant’" (Qur''an 2:67).

It would have been enough for them to slaughter any cow. Yet they multiplied questions that only made things harder on themselves — about its age, then its colour, then its kind. "They said, ‘Call upon your Lord for us to make clear to us what it is.’ He said, ‘He says, it is a cow neither old nor virgin, but median between that…’" (Qur''an 2:68). They asked again about its colour, and were answered, "…it is a yellow cow, bright in colour, pleasing to the observers" (Qur''an 2:69). They still asked more, and at last a very specific description was given, "…a cow neither trained to plow the earth nor to irrigate the field, sound, with no blemish upon her." Only then did they say, "‘Now you have come with the truth.’ So they slaughtered her, but they could hardly do it" (Qur''an 2:71).

Reflection: obeying Allah''s command promptly and with an open heart is best. The more they made it difficult with many questions and excuses, the more Allah narrowed their choices. Ease lies in sincere obedience, not in seeking out reasons to hesitate.

Source & Note: evidence from the Qur''an, 2:67-71 (text & translation from quran-json). The background murder that prompted this command is mentioned briefly in the following verses (72-73); extra details in some reports are outside the text and not asserted here.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 2 AND number = 67), 1301, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1302, 'Episode 2: Yang Terbunuh Dihidupkan untuk Bersaksi', 'Tim Editorial ULYAH', 'ebooks/kisah-sapi-betina/id/kisah-sapi-betina-02-yang-mati-dihidupkan.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-Baqarah 72-73 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: Yang Terbunuh Dihidupkan untuk Bersaksi', 'kisah-sapi-betina-02-yang-mati-dihidupkan', 'id', 'kisah-sapi-betina', 2, 5, 'Al-Qur''an lalu menyingkap latar di balik perintah itu: ada seseorang yang terbunuh, lalu terjadi saling tuduh dan menyembunyikan pelakunya. Allah berfirman, "Dan (ingatlah) ketika kamu membunuh seseorang, lalu kamu tuduh-menuduh tentang itu. Tetapi Allah menyingkapkan apa yang kamu sembunyikan" (QS. Al-Baqarah: 72).

Maka Allah memerintahkan agar mayat itu dipukul dengan sebagian tubuh sapi yang telah disembelih. Dengan izin Allah, orang yang telah mati itu hidup kembali dan memberitahukan siapa pembunuhnya, lalu kembali mati. Allah berfirman, "Lalu Kami berfirman, ‘Pukullah (mayat) itu dengan sebagian (anggota tubuh) sapi betina itu!’ Demikianlah Allah menghidupkan (orang) yang telah mati, dan Dia memperlihatkan kepadamu tanda-tanda (kekuasaan-Nya) agar kamu mengerti" (QS. Al-Baqarah: 73).

Peristiwa ini adalah bukti nyata kuasa Allah menghidupkan yang telah mati — dalil yang sama menegaskan kebenaran hari kebangkitan. Sekaligus ia menjadi teguran atas sikap Bani Israil yang keras hati: mereka menyaksikan mukjizat menghidupkan orang mati, namun tetap banyak yang membatu hatinya (lihat lanjutan QS. Al-Baqarah: 74).

Hikmah: tidak ada yang tersembunyi dari Allah; kejahatan yang ditutup-tutupi pasti disingkap-Nya. Dan Dzat yang mampu menghidupkan satu jiwa yang telah mati pasti mampu membangkitkan seluruh manusia di hari kiamat. Mukjizat sebesar apa pun tidak berguna bagi hati yang enggan tunduk; yang dibutuhkan adalah kelembutan hati untuk beriman.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Al-Baqarah: 72-73 (dan konteks ayat 74). Menghidupkan orang mati dengan memukulkan bagian sapi adalah nas Al-Qur''an. Rincian seperti bagian tubuh sapi mana yang dipakai, dalam sebagian riwayat, tidak disebut secara pasti dalam nas dan tidak dipastikan di sini.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 2 AND number = 72), 1302, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1303, 'Episode 2: The Slain Man Brought to Life to Bear Witness', 'Tim Editorial ULYAH', 'ebooks/kisah-sapi-betina/en/kisah-sapi-betina-02-yang-mati-dihidupkan.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-Baqarah 72-73 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: The Slain Man Brought to Life to Bear Witness', 'kisah-sapi-betina-02-yang-mati-dihidupkan', 'en', 'kisah-sapi-betina', 2, 5, 'The Qur''an then uncovers the background behind that command: a person had been slain, and there was mutual accusation while the killer was concealed. Allah said, "And when you slew a man and disputed over it, but Allah was to bring out that which you were concealing" (Qur''an 2:72).

So Allah commanded that the slain body be struck with part of the slaughtered cow. By Allah''s leave, the dead man came back to life and told who his killer was, then died again. Allah said, "So We said, ‘Strike him with part of it.’ Thus does Allah bring the dead to life, and He shows you His signs that you might reason" (Qur''an 2:73).

This event is a clear proof of Allah''s power to bring the dead to life — the very evidence that affirms the truth of the resurrection. It was also a rebuke to the hard-heartedness of the Children of Israel: they witnessed the miracle of the dead being raised, yet many of their hearts still hardened (see the following verse, Qur''an 2:74).

Reflection: nothing is hidden from Allah; a crime that is covered up will surely be uncovered by Him. And the One able to bring a single dead soul to life is surely able to resurrect all of mankind on the Day of Judgment. No miracle, however great, benefits a heart unwilling to submit; what is needed is a softness of heart that leads to faith.

Source & Note: evidence from the Qur''an, 2:72-73 (and the context of verse 74). Bringing the dead to life by striking him with part of the cow is the Qur''an''s own text. Details such as which part of the cow was used, found in some reports, are not stated with certainty in the text and are not asserted here.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 2 AND number = 72), 1303, datetime('now');

